// Function untuk kirim CAPI
function sendMetaCAPIEvent($access_token, $pixel_id, $event_name, $user_data, $custom_data = [], $event_id = null) {
    if (!$event_id) {
        $event_id = uniqid('event_', true);
    }

    $capi_url = 'https://graph.facebook.com/v20.0/' . $pixel_id . '/events';
    
    $data = [
        'data' => [
            [
                'event_name' => $event_name,
                'event_time' => time(),
                'event_id' => $event_id,
                'action_source' => 'website',
                'user_data' => $user_data,
                'custom_data' => $custom_data
            ]
        ],
        'access_token' => $access_token
    ];

    $ch = curl_init($capi_url);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));
    curl_setopt($ch, CURLOPT_HTTPHEADER, [
        'Content-Type: application/json'
    ]);
    curl_setopt($ch, CURLOPT_TIMEOUT, 5); // Timeout 5 detik
    curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false); // Untuk speed (opsional)

    $response = curl_exec($ch);
    curl_close($ch);

    return $response;
}

// Tangkap parameter UUID atau ID (untuk transaksi lama)
$uuid = get('uuid');
$transaksi_id_lama = (int) get('id');

if ($uuid) {
    // Cari berdasarkan UUID baru
    $transaksi = fetchRow("
        SELECT t.*, p.nama as nama_customer, p.nomor_wa, p.email 
        FROM transaksi t 
        JOIN pelanggan p ON t.pelanggan_id = p.id 
        WHERE t.uuid = ?
    ", [$uuid]);
} elseif ($transaksi_id_lama) {
    // Fallback: Cari berdasarkan ID lama
    $transaksi = fetchRow("
        SELECT t.*, p.nama as nama_customer, p.nomor_wa, p.email 
        FROM transaksi t 
        JOIN pelanggan p ON t.pelanggan_id = p.id 
        WHERE t.id = ?
    ", [$transaksi_id_lama]);
} else {
    redirect('index.php');
}

if (!$transaksi) {
    setMessage('Invoice tidak ditemukan', 'error');
    redirect('index.php');
}

// Ambil ID asli untuk query database di bawahnya (detail_produk)
