    setMessage('Invoice tidak ditemukan', 'error');
    redirect('index.php');
}

// Get transaction details with products
$detail_produk = fetchAll("
    SELECT dt.*, pr.nama, pr.link_akses, pr.admin_wa, pr.meta_pixel_id, pr.conversion_api_token, pr.onesender_account 
    FROM detail_transaksi dt 
    JOIN produk pr ON dt.produk_id = pr.id 
    WHERE dt.transaksi_id = ?
", [$transaksi_id]);

$main_product = $detail_produk[0];

// Get bank accounts
$rekening = fetchAll("SELECT * FROM rekening ORDER BY nama_bank");

// Send invoice message if first time
if ($transaksi['is_invoice_sent'] == 0 && $transaksi['status'] === 'pending') {
    
    $template = fetchRow("SELECT isi_pesan FROM template_pesan_produk WHERE produk_id = ? AND jenis_pesan = 'invoice'", [$main_product['produk_id']]);
    
    if ($template && !empty($template['isi_pesan'])) {
        $template_data = [
            'nama_customer' => $transaksi['nama_customer'],
            'nomor_wa' => $transaksi['nomor_wa'],
            'email_customer' => $transaksi['email'] ?? '-', // <--- BARU
            'id_transaksi' => $transaksi_id,
            'total_harga' => $transaksi['total_harga'],
            'tanggal' => date('d/m/Y'),
            'waktu' => date('H:i'),
        ];
        
        if (count($detail_produk) > 1) {
            $produk_list = [];
            foreach ($detail_produk as $produk) {
                $produk_list[] = [
                    'nama' => $produk['nama'],
                    'harga' => $produk['harga'],
                    'link_akses' => $produk['link_akses']
                ];
            }
            $template_data['produk_list'] = $produk_list;
        } else {
            $template_data['nama_produk'] = $main_product['nama'];
            $template_data['harga_produk'] = $main_product['harga'];
            $template_data['link_akses'] = $main_product['link_akses'];
        }
        
        $message = replaceTemplatePlaceholders($template['isi_pesan'], $template_data);
        $account_name = $main_product['onesender_account'] ?? 'default';
        
        // Eksekusi kirim pesan
        $result = sendWhatsAppText($transaksi['nomor_wa'], $message, $account_name);
        
        // UPDATE DATABASE: Tandai sudah dikirim (set jadi 1)
        execute("UPDATE transaksi SET is_invoice_sent = 1 WHERE id = ?", [$transaksi_id]);
        
        // Update variabel lokal agar UI sinkron (opsional)
        $transaksi['is_invoice_sent'] = 1;
    }
}

// Handle payment confirmation
if (isPost() && post('action') === 'confirm_payment') {
    $admin_wa = $main_product['admin_wa'];
    if ($admin_wa) {
        $message = "Assalamualaikum Admin, saya mau konfirmasi pembayaran untuk Invoice #$invoice_display atas nama {$transaksi['nama_customer']} dengan total " . formatCurrency($transaksi['total_harga']);
        $wa_link = whatsappLink($admin_wa, $message);
        redirect($wa_link);
    }
}

// Kirim AddPaymentInfo ke CAPI saat halaman dibuka pertama kali
if ($transaksi['status'] === 'pending' && !isset($_SESSION['addpaymentinfo_sent_' . $transaksi_id])) {
    if (!empty($main_product['conversion_api_token']) && !empty($main_product['meta_pixel_id'])) {
        $user_data = [
            'ph' => hash('sha256', $transaksi['nomor_wa']),
            'client_ip_address' => $_SERVER['REMOTE_ADDR'] ?? '',
            'client_user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? ''
        ];
        if (!empty($transaksi['fbc'])) $user_data['fbc'] = $transaksi['fbc'];
        if (!empty($transaksi['fbp'])) $user_data['fbp'] = $transaksi['fbp'];

        $contents = [];
        $content_ids = [];
        foreach ($detail_produk as $produk) {
            $contents[] = [
                'id' => (string) $produk['produk_id'],
                'quantity' => 1
            ];
            $content_ids[] = (string) $produk['produk_id'];
        }
        $custom_data = [
            'currency' => 'IDR',
            'value' => (float) $transaksi['total_harga'],
            'content_ids' => $content_ids,
            'contents' => $contents,
            'content_type' => 'product'
        ];

        $event_id = 'addpaymentinfo_' . $transaksi_id;

        sendMetaCAPIEvent(
            $main_product['conversion_api_token'],
            $main_product['meta_pixel_id'],
            'AddPaymentInfo',
            $user_data,
            $custom_data,
            $event_id 
        );

        $_SESSION['addpaymentinfo_sent_' . $transaksi_id] = true;
    }
}

