<script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js" defer></script>
<script>
function copyToClipboard(t){
    navigator.clipboard.writeText(t).then(function(){
        const e=document.createElement("div");
        e.className="position-fixed top-0 end-0 m-3 alert alert-success alert-dismissible fade show";
        e.style.borderRadius = "12px";
        e.style.boxShadow = "0 10px 20px rgba(0,0,0,0.1)";
        e.style.zIndex = "9999";
        e.innerHTML='<i class="fas fa-check-circle me-2"></i> Nomor rekening berhasil disalin! <button type="button" class="btn-close" data-bs-dismiss="alert"></button>';
        document.body.appendChild(e);
        setTimeout(()=>{e.parentNode&&new bootstrap.Alert(e).close()},3e3);
    }).catch(function(){alert("Gagal menyalin: "+t)});
}

<?php if ($transaksi['status'] === 'pending'): ?>
function startCountdown(){
    const t=new Date("<?= $transaksi['tanggal_transaksi'] ?>").getTime();
    const e=t+864e5; // 24 jam
    const n=document.getElementById("countdown");
    if(!n) return;
    
    function o(){
        const t=(new Date).getTime();
        const o=e-t;
        if(o<0){
            n.innerHTML="WAKTU HABIS";
            n.style.color = "var(--status-batal-text)";
            return;
        }
        const r=Math.floor(o%(864e5)/36e5);
        const i=Math.floor(o%(36e5)/6e4);
        const c=Math.floor(o%(6e4)/1e3);
        n.innerHTML=String(r).padStart(2,"0")+":"+String(i).padStart(2,"0")+":"+String(c).padStart(2,"0");
    }
    o();
    setInterval(o,1e3);
}
startCountdown();
<?php endif; ?>

function showQRISImage(t,e,n){
    if(!t||""===t.trim()||"null"===t) return void alert("Data QRIS belum lengkap. Silakan hubungi admin.");
    document.getElementById("qris-image").src=t;
    document.getElementById("qris-merchant-name").textContent=e;
    document.getElementById("qris-amount").textContent=n;
    document.getElementById("qris-amount-reminder").textContent=n;
    const o=new bootstrap.Modal(document.getElementById("qrisModal"));
    o.show();
    document.getElementById("qris-image").onerror=function(){
        alert("Gagal memuat gambar QRIS dari server.");
        o.hide();
    };
    document.getElementById("downloadQRButton").onclick=function(){downloadQRImage(t)};
}

function downloadQRImage(url) {
    const btn = document.getElementById("downloadQRButton");
    const originalText = btn.innerHTML;
    
    btn.innerHTML = '<i class="fas fa-spinner fa-spin me-2"></i>Mengunduh...';
    btn.disabled = true;

    fetch(url)
        .then(response => response.blob())
        .then(blob => {
            const blobUrl = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.style.display = 'none';
            a.href = blobUrl;
            a.download = "QRIS_Invoice_<?= $transaksi_id ?>.png"; 
            document.body.appendChild(a);
            a.click();
            
            window.URL.revokeObjectURL(blobUrl);
            a.remove();
            
            btn.innerHTML = originalText;
            btn.disabled = false;
        })
        .catch(err => {
            console.error('Error downloading QR:', err);
            alert('Gagal mengunduh gambar QRIS. Silakan screenshot layar ini.');
            btn.innerHTML = originalText;
            btn.disabled = false;
        });
}
</script>

